     4→import { Flame, Trophy, BookOpen, Zap } from 'lucide-react';
     5→import { Card, CardContent } from '@/components/ui/card';
     6→import { cn } from '@/lib/utils';
     7→import type { Progress } from '@/types';
     8→
     9→interface ProgressCardProps {
    10→  progress: Progress;
    11→  className?: string;
    12→}
    13→
    14→export function ProgressCard({ progress, className }: ProgressCardProps) {
    15→  const xpProgress = (progress.xp % progress.xpToNextLevel) / progress.xpToNextLevel * 100;
    16→
    17→  return (
    18→    <Card className={cn('overflow-hidden', className)}>
    19→      <CardContent className="p-6">
    20→        {/* Level and XP */}
    21→        <div className="flex items-center justify-between mb-4">
    22→          <div className="flex items-center gap-3">
    23→            <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-purple-500 to-indigo-600 flex items-center justify-center">
    24→              <span className="text-xl font-bold text-white">{progress.level}</span>
    25→            </div>
    26→            <div>
    27→              <p className="text-sm text-slate-500 dark:text-slate-400">Livello</p>
    28→              <p className="font-semibold">Studente {getLevelTitle(progress.level)}</p>
    29→            </div>
    30→          </div>
    31→          <div className="text-right">
    32→            <p className="text-2xl font-bold text-purple-600">{progress.xp.toLocaleString()}</p>
    33→            <p className="text-xs text-slate-500">XP totali</p>
    34→          </div>
    35→        </div>
    36→
    37→        {/* XP Progress bar */}
    38→        <div className="mb-6">
    39→          <div className="flex justify-between text-xs text-slate-500 mb-1">
    40→            <span>Prossimo livello</span>
    41→            <span>{progress.xpToNextLevel - (progress.xp % progress.xpToNextLevel)} XP rimanenti</span>
    42→          </div>
    43→          <div className="h-3 bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
    44→            <motion.div
    45→              className="h-full bg-gradient-to-r from-purple-500 to-indigo-500"
    46→              initial={{ width: 0 }}
    47→              animate={{ width: `${xpProgress}%` }}
    48→              transition={{ duration: 1, ease: 'easeOut' }}
    49→            />
    50→          </div>
    51→        </div>
    52→
    53→        {/* Stats grid */}
    54→        <div className="grid grid-cols-4 gap-4">
    55→          <StatItem
    56→            icon={<Flame className="w-5 h-5 text-orange-500" />}
    57→            value={progress.streak.current}
    58→            label="Streak"
    59→            highlight={progress.streak.current >= 7}
    60→          />
    61→          <StatItem
    62→            icon={<Trophy className="w-5 h-5 text-amber-500" />}
    63→            value={progress.achievements.filter(a => a.unlockedAt).length}
    64→            label="Trofei"
    65→          />
    66→          <StatItem
    67→            icon={<BookOpen className="w-5 h-5 text-blue-500" />}
    68→            value={progress.sessionsThisWeek}
    69→            label="Sessioni"
    70→          />
    71→          <StatItem
    72→            icon={<Zap className="w-5 h-5 text-purple-500" />}
    73→            value={progress.questionsAsked}
    74→            label="Domande"
    75→          />
    76→        </div>
    77→      </CardContent>
    78→    </Card>
    79→  );
    80→}
    81→
    82→interface StatItemProps {
    83→  icon: React.ReactNode;
    84→  value: number;
    85→  label: string;
    86→  highlight?: boolean;
    87→}
    88→
    89→function StatItem({ icon, value, label, highlight }: StatItemProps) {
    90→  return (
