   296→// === PROGRESS STORE (Gamification) ===
   297→
   298→// Session grade given by maestro (1-10 scale)
   299→export interface SessionGrade {
   300→  score: number; // 1-10
   301→  feedback: string;
   302→  strengths: string[];
   303→  areasToImprove: string[];
   304→}
   305→
   306→interface StudySession {
   307→  id: string;
   308→  maestroId: string;
   309→  subject: string;
   310→  startedAt: Date;
   311→  endedAt?: Date;
