   333→  // Actions
   334→  addXP: (amount: number) => void;
   335→  updateStreak: () => void;
   336→  updateMastery: (subjectMastery: SubjectMastery) => void;
   337→  unlockAchievement: (achievementId: string) => void;
   338→  addStudyMinutes: (minutes: number) => void;
   339→  incrementQuestions: () => void;
   340→  // Session actions
