   342→  endSession: (grade?: SessionGrade) => void;
   343→  gradeCurrentSession: (grade: SessionGrade) => void;
   344→  // Sync actions
   345→  syncToServer: () => Promise<void>;
   346→  loadFromServer: () => Promise<void>;
   347→}
   348→
   349→const XP_PER_LEVEL = [
   350→  0, 100, 250, 500, 1000, 2000, 4000, 8000, 16000, 32000, 64000,
   351→];
   352→
   353→export const useProgressStore = create<ProgressState>()(
   354→  (set, get) => ({
   355→      xp: 0,
   356→      level: 1,
   357→      streak: { current: 0, longest: 0 },
   358→      masteries: [],
   359→      achievements: [],
   360→      totalStudyMinutes: 0,
   361→      sessionsThisWeek: 0,
   362→      questionsAsked: 0,
   363→      currentSession: null,
   364→      sessionHistory: [],
   365→      lastSyncedAt: null,
   366→      pendingSync: false,
